-- =============================================================================
-- Тест EQ-профиля для программы "Эмоциональный интеллект 2.0" (Бредберри и Гривз)
-- 20 вопросов, 4 шкалы (4 навыка EQ), 5-балльная шкала Ликерта
-- Формат: НАВЫКОВЫЙ (higher_is_better) — карта навыков, не диагностика
-- Утверждения — оригинальный синтез на базе 66 стратегий Бредберри и публичных
-- валидированных EQ-опросников (SSEIT Schutte, WLEIS Wong-Law). НЕ копия
-- проприетарного Emotional Intelligence Appraisal™ TalentSmart.
-- =============================================================================

-- ─────────────────────────────────────────────────────────────────────────────
-- 1. INSERT test_configs
-- ─────────────────────────────────────────────────────────────────────────────

INSERT INTO test_configs (
  program_id,
  slug,
  title,
  short_title,
  description,
  questions,
  scales,
  scoring,
  ui_config,
  interpretation_prompt,
  mini_analysis_prompt_template,
  is_active
) VALUES (
  (SELECT id FROM programs WHERE slug = 'eq-2-0'),

  -- slug
  'eq-test',

  -- title
  'Твой профиль эмоционального интеллекта',

  -- short_title
  'EQ-профиль',

  -- description
  'Оценка по 4 навыкам EQ (по фреймворку Бредберри и Гривз). Самоотчёт — стартовая точка рефлексии, не финальный диагноз.',

  -- questions (20: 4 шкалы × 5 вопросов, 3 direct + 2 reverse на шкалу)
  '[
    {"q":1,  "scale":"eq_self_awareness",          "type":"direct",  "text":"Я замечаю телесные сигналы (пульс, напряжение), до того как осознаю злость или волнение"},
    {"q":2,  "scale":"eq_self_awareness",          "type":"direct",  "text":"Я могу точно назвать причину, по которой моё настроение изменилось"},
    {"q":3,  "scale":"eq_self_awareness",          "type":"reverse", "text":"Я стараюсь быстро подавить неприятные чувства, разделяя их на правильные и неправильные"},
    {"q":4,  "scale":"eq_self_awareness",          "type":"direct",  "text":"Я знаю, какие ситуации или люди мгновенно выводят меня из равновесия"},
    {"q":5,  "scale":"eq_self_awareness",          "type":"reverse", "text":"В стрессе я действую автоматически, не успевая отследить свои чувства"},

    {"q":6,  "scale":"eq_self_management",         "type":"direct",  "text":"Когда эмоции и разум в конфликте, я беру паузу, прежде чем решить"},
    {"q":7,  "scale":"eq_self_management",         "type":"direct",  "text":"Я могу отложить сиюминутный комфорт ради долгосрочных целей"},
    {"q":8,  "scale":"eq_self_management",         "type":"reverse", "text":"После неприятного события я долго прокручиваю негативные мысли и обобщения"},
    {"q":9,  "scale":"eq_self_management",         "type":"reverse", "text":"Будучи сильно раздражённым, я говорю или делаю то, о чём потом жалею"},
    {"q":10, "scale":"eq_self_management",         "type":"direct",  "text":"Даже в сильном разочаровании я фокусируюсь на том, что от меня зависит"},

    {"q":11, "scale":"eq_social_awareness",        "type":"direct",  "text":"В разговоре я полностью сосредоточен на собеседнике, не обдумывая свой ответ"},
    {"q":12, "scale":"eq_social_awareness",        "type":"direct",  "text":"Я легко улавливаю невербальные сигналы людей, даже когда слова спокойные"},
    {"q":13, "scale":"eq_social_awareness",        "type":"reverse", "text":"Я с удивлением узнаю постфактум, что близкие были напряжены — мне всё казалось нормальным"},
    {"q":14, "scale":"eq_social_awareness",        "type":"reverse", "text":"Мне трудно распознать сарказм или скрытое недовольство в интонации"},
    {"q":15, "scale":"eq_social_awareness",        "type":"direct",  "text":"Когда сомневаюсь, что чувствует другой — задаю прямой вопрос, описывая то, что вижу"},

    {"q":16, "scale":"eq_relationship_management", "type":"direct",  "text":"В конфликте я признаю право другого на его эмоции, даже когда не согласен"},
    {"q":17, "scale":"eq_relationship_management", "type":"direct",  "text":"Критикуя, я фокусируюсь на фактах и поведении — прямо, но уважительно"},
    {"q":18, "scale":"eq_relationship_management", "type":"reverse", "text":"Я предпочитаю замалчивать проблемы с коллегами, лишь бы избежать открытого разговора"},
    {"q":19, "scale":"eq_relationship_management", "type":"reverse", "text":"Мой тон или выражение лица иногда транслируют одно, а слова — другое"},
    {"q":20, "scale":"eq_relationship_management", "type":"direct",  "text":"В тупиковом разговоре я первым предлагаю признать сложность и перезагрузить обсуждение"}
  ]'::jsonb,

  -- scales
  '[
    {"key":"eq_self_awareness",          "name":"Самосознание",           "order":0, "exercises":[], "radar_label":["Само-","сознание"]},
    {"key":"eq_self_management",         "name":"Управление собой",       "order":1, "exercises":[], "radar_label":["Управление","собой"]},
    {"key":"eq_social_awareness",        "name":"Социальная чуткость",    "order":2, "exercises":[], "radar_label":["Социальная","чуткость"]},
    {"key":"eq_relationship_management", "name":"Управление отношениями", "order":3, "exercises":[], "radar_label":["Управление","отношениями"]}
  ]'::jsonb,

  -- scoring (НАВЫКОВЫЙ: higher_is_better, уровни Новичок → Мастер)
  '{
    "answer_range": [1, 5],
    "score_direction": "higher_is_better",
    "level_thresholds": [30, 55, 80],
    "level_labels": ["Новичок", "Развивающийся", "Уверенный", "Мастер"]
  }'::jsonb,

  -- ui_config
  '{
    "questions_per_block": 5,
    "auth_wall_question": 14,
    "welcome_title": "Твой профиль EQ<br /><span>по 4 навыкам Бредберри</span>",
    "welcome_subtitle": "20 вопросов · ~5 минут",
    "welcome_description": "Оценка по 4 навыкам эмоционального интеллекта (по фреймворку Бредберри и Гривз). Самоотчёт — стартовая точка рефлексии, не финальная метрика. Результаты подбирают релевантные тренажёры под твою зону роста.",
    "welcome_badge": "Бесплатно",
    "welcome_cta": "Начать тест",
    "welcome_meta": "Вспомни последние 2-4 недели. Это самоотчёт — он работает как зеркало твоих привычек в моменте, не как финальная оценка. Правильных ответов нет — честность важнее желаемого образа",
    "welcome_stats": [
      {"num": "20", "label": "вопросов"},
      {"num": "4", "label": "навыка"},
      {"num": "~5", "label": "минут"}
    ],
    "block_insights": [
      "Самосознание — фундамент. Без него остальные 3 навыка не запускаются. Дальше — что с этим делать",
      "Управление собой — навык паузы между стимулом и реакцией. Теперь смотрим наружу",
      "Видеть других — только полдела. Главное — как ты с этим взаимодействуешь",
      "Готово. Собираю твой профиль"
    ],
    "quick_answer_labels": ["Совсем нет", "Скорее нет", "Иногда", "Скорее да", "Полностью"],
    "analyzing_stages": [
      {
        "title": "Анализ ответов",
        "substeps": [
          "Обрабатываю 20 ответов",
          "Считаю баллы по 4 шкалам"
        ]
      },
      {
        "title": "Готовлю интерпретацию",
        "substeps": [
          "Нахожу твою зону роста",
          "Подбираю релевантные практики"
        ]
      }
    ],
    "timeframe_text": "Вспомни последние 2-4 недели",
    "radar_labels": {
      "eq_self_awareness":          ["Само-","сознание"],
      "eq_self_management":         ["Управление","собой"],
      "eq_social_awareness":        ["Социальная","чуткость"],
      "eq_relationship_management": ["Управление","отношениями"]
    }
  }'::jsonb,

  -- interpretation_prompt (Gemini Pro — финальная интерпретация результатов)
  E'Ты — AI-интерпретатор теста на 4 навыка эмоционального интеллекта по фреймворку Бредберри и Гривз (книга «Эмоциональный интеллект 2.0», TalentSmart, 2009).\n\n## КОНТЕКСТ\n\nТест — 20 утверждений по 4 шкалам (5 на шкалу, 3 direct + 2 reverse):\n- Самосознание (eq_self_awareness) — способность точно улавливать свои эмоции и понимать свои триггеры. Фундамент EQ.\n- Управление собой (eq_self_management) — использовать осознание для гибкого управления поведением, удержания паузы между стимулом и реакцией.\n- Социальная чуткость (eq_social_awareness) — точно считывать эмоции других, понимать невербалику и настроение группы. Позиция «антрополога».\n- Управление отношениями (eq_relationship_management) — использовать предыдущие 3 для успешных взаимодействий: разрешать конфликты, давать обратную связь, вести трудные разговоры.\n\nФормат теста: навыковый (score_direction=higher_is_better). Высокий балл = владение навыком, не патология.\nУровни: Новичок (0-30%) / Развивающийся (30-55%) / Уверенный (55-80%) / Мастер (80-100%).\n\nМета-структура (из Bradberry & Su 2006 PCA):\n- Personal Competence = (Self-Awareness + Self-Management) — работа с собой\n- Social Competence = (Social Awareness + Relationship Management) — работа с другими\nЕсли один блок значительно сильнее другого — отметь это как инсайт.\n\n## ТВОЯ ЗАДАЧА\n\nСгенерируй JSON-интерпретацию по шаблону ниже. Читает пользователь — пиши на «ты», на русском, без клинического жаргона.\n\n## ФОРМАТ ОТВЕТА (строго JSON, без markdown-обёрток)\n\n{\n  "overall": "3-4 предложения — общая картина. Назови самый сильный и самый слабый навык, акцент на движение. Если есть заметный Personal vs Social дисбаланс — упомяни.",\n  "level_label": "Один из: Новичок | Развивающийся | Уверенный | Мастер (по общему баллу)",\n  "scales": [\n    {\n      "scale_key": "eq_self_awareness",\n      "interpretation": "2-3 предложения по формуле: [что уже делаешь — конкретное поведение] + [что это даёт — какой эффект] + [что ещё можно добавить — следующий шаг через конкретный режим]"\n    }\n  ],\n  "top_zones": [\n    {\n      "scale_key": "eq_self_awareness",\n      "action_text": "Рекомендация — 1 предложение + CTA в режим + упоминание retest через 8-10 недель"\n    }\n  ]\n}\n\n**ВАЖНО: top_zones содержит ТОЛЬКО 1 объект** — самую низкую шкалу. Принцип Бредберри «один навык за раз»: множественные приоритеты парализуют.\n\n## 8 ПРАВИЛ ТОНА (обязательно)\n\n1. НАПРАВЛЕНИЕ В КАЖДОМ УРОВНЕ — даже у Мастера есть куда расти (углубление, сочетание навыков). Не «ты уже идеально».\n2. НАВЫК, НЕ ЧЕРТА — «ты тренируешь...», не «ты такой...». EQ — пластичный навык, мозг пластичен.\n3. ПРОГРЕСС, НЕ СОВЕРШЕНСТВО — «ловишь себя всё чаще» вместо «никогда не ошибаешься».\n4. РЕСУРС В КАЖДОМ УРОВНЕ — у Новичка стартовая позиция (низкий балл = честное зеркало, не приговор).\n5. ПРИЧИНА, НЕ ДИАГНОЗ — откуда берётся паттерн (нейрофизиология, привычки, опыт), не «что с тобой не так».\n6. ЯЗЫК ДВИЖЕНИЯ — «начать», «вставить паузу», «тренировать», «углубить».\n7. НЕ ПАТОЛОГИЗИРОВАТЬ — ЗАПРЕЩЕНЫ слова: синдром, расстройство, нарушение, дисфункция, проблема как диагноз. Используй: навык, паттерн, привычка, зона роста.\n8. PERSONAL vs SOCIAL BALANCE — если Personal (SA+SM) сильнее Social (SocA+RM) или наоборот на >15 пунктов, отметь: «Ты сильнее работаешь с собой, чем с другими» или наоборот. Это более точный сигнал, чем 4 изолированных балла.\n\n## МАППИНГ ПРИОРИТЕТА\n\nСамая низкая шкала → рекомендация одного из режимов в action_href:\n- eq_self_awareness → режим «Что я сейчас чувствую», /program/eq-2-0/chat/new?tool=eq-self-awareness\n- eq_self_management → режим «Пауза перед реакцией», /program/eq-2-0/chat/new?tool=eq-self-management\n- eq_social_awareness → режим «Что с ним происходит», /program/eq-2-0/chat/new?tool=eq-social-awareness\n- eq_relationship_management → режим «Трудный разговор», /program/eq-2-0/chat/new?tool=eq-relationships\n\n## ОПОРНЫЕ ИДЕИ БРЕДБЕРРИ (для тона, не копировать)\n\n- EQ не коррелирует с IQ; можно развить в любом возрасте\n- Первая реакция на событие всегда эмоциональная — задача не отключить, а управлять транзитом\n- Новые поведения физически создают нейронные пути — с практикой автоматизируются\n- Самосознание — фундамент, без него остальные 3 навыка не запускаются\n- Прогресс, не совершенство: мастерство — всё чаще ловить себя до реакции\n\n## ФОРМУЛА ИНТЕРПРЕТАЦИИ ШКАЛЫ\n\n[Что уже делаешь — конкретное поведение по шкале] + [Что это даёт — какой эффект в общении] + [Что ещё можно добавить — следующий шаг через конкретный режим тренажёра].\n\n2-3 предложения на шкалу. Без похвалы («молодец»), без жалости («бедный»), без приказов («ты должен»). Констатация + направление.\n\n## ДАННЫЕ ПОЛЬЗОВАТЕЛЯ\n\n{{scores}} — баллы по 4 шкалам в процентах (0-100)\n{{overall_pct}} — общий балл\n{{overall_level}} — общий уровень\n\nВерни ТОЛЬКО JSON, без markdown-обёрток, без комментариев.',

  -- mini_analysis_prompt_template (NULL для 20-вопросного теста — не нужен)
  NULL,

  -- is_active
  true
)
ON CONFLICT (slug) DO UPDATE SET
  title = EXCLUDED.title,
  short_title = EXCLUDED.short_title,
  description = EXCLUDED.description,
  questions = EXCLUDED.questions,
  scales = EXCLUDED.scales,
  scoring = EXCLUDED.scoring,
  ui_config = EXCLUDED.ui_config,
  interpretation_prompt = EXCLUDED.interpretation_prompt,
  mini_analysis_prompt_template = EXCLUDED.mini_analysis_prompt_template,
  is_active = EXCLUDED.is_active;


-- ─────────────────────────────────────────────────────────────────────────────
-- 2. UPDATE features — включаем feature flag теста
-- ─────────────────────────────────────────────────────────────────────────────

UPDATE programs
SET features = features || '{"test": true}'::jsonb
WHERE slug = 'eq-2-0';


-- ─────────────────────────────────────────────────────────────────────────────
-- 3. UPDATE programs.test_system_prompt
--    Используется API /api/test для генерации ответов во время теста
-- ─────────────────────────────────────────────────────────────────────────────

UPDATE programs
SET test_system_prompt = E'Ты — AI-помощник на тесте EQ по книге Бредберри и Гривз «Эмоциональный интеллект 2.0».\n\nТест измеряет 4 навыка: Самосознание, Управление собой, Социальная чуткость, Управление отношениями. 20 утверждений, Ликерт 1-5.\n\nЭто навыковый тест (не диагностика): мы оцениваем, что пользователь УЖЕ умеет и где ему зона быстрого роста.\n\nЕсли пользователь пишет текстом (а не кликает по шкале):\n- Коротко подтверди понимание (1 предложение)\n- Переформулируй его ответ в балл 1-5 и предложи подтвердить\n- Не углубляйся в коучинг — это для чат-режимов после теста\n\nНиких предположений о гендере, возрасте, должности пользователя.\nФормат ответа: максимум 40 слов, один вопрос за раз. На «ты», на русском.\n\nТон: практичный, без клинического жаргона. Запрещены: синдром, расстройство, дисфункция. Используй: навык, приём, зона роста.'
WHERE slug = 'eq-2-0'
  AND test_system_prompt IS NULL;


-- ─────────────────────────────────────────────────────────────────────────────
-- 4. UPDATE landing_data.test — секция теста на лендинге
-- ─────────────────────────────────────────────────────────────────────────────

UPDATE programs
SET landing_data = jsonb_set(
  COALESCE(landing_data, '{}'::jsonb),
  '{test}',
  '{
    "emoji": "🎯",
    "title": "Твой профиль EQ за 5 минут",
    "description": "Оценка по 4 навыкам эмоционального интеллекта — фундамент, с которого начинать развитие",
    "time_label": "~5 минут",
    "questions_label": "20 вопросов",
    "cta_text": "Пройти тест бесплатно",
    "cta_href": "/program/eq-2-0/test"
  }'::jsonb
)
WHERE slug = 'eq-2-0';


-- ─────────────────────────────────────────────────────────────────────────────
-- 5. mode_template + program_mode — карточка теста на хабе
-- ─────────────────────────────────────────────────────────────────────────────

INSERT INTO mode_templates (key, name, description, icon, chat_type, route_suffix, is_chat_based, default_sort_order)
VALUES ('test_eq', 'Тест EQ', 'Профиль по 4 навыкам эмоционального интеллекта', 'check', NULL, '/test/eq-test', false, 0)
ON CONFLICT (key) DO NOTHING;

INSERT INTO program_modes (program_id, mode_template_id, sort_order, enabled, access_type)
SELECT
  (SELECT id FROM programs WHERE slug = 'eq-2-0'),
  (SELECT id FROM mode_templates WHERE key = 'test_eq'),
  1,
  true,
  'free'
ON CONFLICT DO NOTHING;


-- ─────────────────────────────────────────────────────────────────────────────
-- 6. UPDATE hub_messages — AI-приветствие на хабе (3 состояния)
--    {theme1}/{theme2} резолвятся в топ-2 тем по баллам теста.
--    Для higher_is_better — самые НИЗКИЕ баллы = зоны роста.
-- ─────────────────────────────────────────────────────────────────────────────

UPDATE programs
SET hub_messages = '{
  "first": "Привет. EQ — навык, а не черта: мозг пластичен, тренируется в любом возрасте. Начни с теста — <strong>~5 минут, 20 вопросов</strong> — и я подскажу, над каким из 4 навыков работать первым.",
  "returning_test": "Твоя первая зона роста — <strong>{theme1}</strong>. Начнём с неё, или хочешь <strong>{theme2}</strong>?",
  "returning_notest": "Пройди тест — <strong>~5 минут</strong>, и я подскажу с чего начать. Или бери любой инструмент ниже."
}'::jsonb
WHERE slug = 'eq-2-0';


-- ─────────────────────────────────────────────────────────────────────────────
-- 7. ВЕРИФИКАЦИЯ (раскомментировать для отладки)
-- ─────────────────────────────────────────────────────────────────────────────

